import { useEffect, useState } from 'react';
import { io } from 'socket.io-client';

export const useWebSocket = () => {
  const [socket, setSocket] = useState(null);
  const [events, setEvents] = useState([]);

  useEffect(() => {
    const client = io(process.env.REACT_APP_API_URL || 'http://localhost:5000', {
      transports: ['polling'],
      reconnection: true,
      reconnectionAttempts: 5,
      reconnectionDelay: 1000,
      timeout: 5000,
    });

    client.on('connect', () => setSocket(client));
    client.on('connect_error', (error) => console.warn('Socket connection failed:', error.message));
    client.on('sync_update', (payload) => setEvents((previous) => [...previous, payload]));
    return () => client.disconnect();
  }, []);

  return { socket, events };
};
